bool solve(std::vector<long long> nums1) {
    int n = nums1.size();
    if (n == 1) {
        return true;
    }

    // 1. Sort the array to easily check the minimum element constraint
    std::sort(nums1.begin(), nums1.end());

    // 2. Precompute O_exists: O_exists[i] is true if nums1[0...i] contains at least one odd number.
    std::vector<bool> O_exists(n, false);
    bool current_odd_found = false;
    for (int i = 0; i < n; ++i) {
        if (nums1[i] % 2 != 0) {
            current_odd_found = true;
        }
        O_exists[i] = current_odd_found;
    }

    // --- Check T=0 (Target Parity: All Even) ---
    bool possible_T0 = true;
    for (int i = 0; i < n; ++i) {
        // If nums1[i] is odd (p_i = 1), we must change its parity to 0 (Even) using subtraction.
        // We need to find j != i such that nums1[j] is odd AND nums1[j] < nums1[i].
        if (nums1[i] % 2 != 0) {
            // Case i=0: nums1[i] is the minimum element. No j < i exists, so subtraction is impossible.
            if (i == 0) {
                possible_T0 = false;
                break;
            }
            // Case i > 0: We need a smaller odd number. Check O_exists[i-1].
            if (!O_exists[i - 1]) {
                possible_T0 = false;
                break;
            }
        }
        // If nums1[i] is even (p_i = 0), we can use Option 1, so it's OK.
    }

    if (possible_T0) return true;


    // --- Check T=1 (Target Parity: All Odd) ---
    bool possible_T1 = true;
    for (int i = 0; i < n; ++i) {
        // If nums1[i] is even (p_i = 0), we must change its parity to 1 (Odd) using subtraction.
        // We need to find j != i such that nums1[j] is odd AND nums1[j] < nums1[i].
