#include <algorithm>
#include <limits>

bool solve(std::vector<long long> nums1) {
    bool has_odd = false;
    bool has_even = false;
    long long min_odd = std::numeric_limits<long long>::max();

    // Step 1: Analyze the composition of nums1
    for (long long x : nums1) {
        if (x % 2 == 0) {
            has_even = true;
        } else {
            has_odd = true;
            if (x < min_odd) {
                min_odd = x;
            }
        }
    }

    // Step 2: Handle uniform cases
    // Case 1: All elements are even. We can choose nums2[i] = nums1[i] (All even).
    if (!has_odd) {
        return true;
    }

    // Case 2: All elements are odd. We can choose nums2[i] = nums1[i] (All odd).
    if (!has_even) {
        return true;
    }

    // Step 3: Mixed parity case. We must aim for Target Parity = Odd.
    // For every even number e in nums1, we must be able to set nums2[i] = e - o (where o is odd, and e > o).
    // This requires e > min_odd for all even e.

    for (long long x : nums1) {
        if (x % 2 == 0) { // x is an even number
            if (x <= min_odd) {
                // This even number x cannot be converted to an odd number by subtracting any available odd number,
                // because all available odd numbers are >= min_odd.
                return false;
            }
        }
    }

    // If all even numbers are strictly greater than the minimum odd number, 
    // we can successfully construct nums2 to be all odd.
    return true;
}

