bool solve(std::vector<long long> nums1) {
    std::vector<long long> odds;
    std::vector<long long> evens;

    for (long long x : nums1) {
        if (x % 2 != 0) {
            odds.push_back(x);
        } else {
            evens.push_back(x);
        }
    }

    // --- Check Possibility 1: All Even ---
    // All Even is only possible if there are no odd numbers in nums1,
    // because the smallest odd number cannot be converted to an even number
    // using the allowed operations (Odd - Odd = Even requires a smaller odd number, which doesn't exist).
    if (odds.empty()) {
        return true;
    }

    // --- Check Possibility 2: All Odd ---

    // If there are odd numbers, we need to check if all even numbers can be converted to odd.
    // To convert an even number E to odd, we must subtract an odd number O (E - O = Odd).

    // If there are no odd numbers, this case was covered above. Since odds is non-empty here:

    // Find the smallest odd number, o_min. This is the best candidate for subtraction
    // as it is most likely to keep the difference positive for even numbers.
    long long o_min = odds[0];
    for (long long o : odds) {
        if (o < o_min) {
            o_min = o;
        }
    }

    // Check if every even number E is strictly greater than o_min.
    for (long long e : evens) {
        if (e <= o_min) {
            // If e <= o_min, we cannot find an odd nums1[j] such that e - nums1[j] >= 1.
            // Since e itself is even, this even number cannot be made odd.
            return false;
        }
    }

    // If all checks pass, All Odd is achievable.
    return true;
}

